/\"), 2)\n| eval user_raw = coalesce(UserId, Target_User_Name, Caller_User_Name, Client_User_Name, xml_user)\n| eval user     = replace(user_raw, \"^the organization-AD\\\\\\\\\", \"\")\n| stats\n    min(_time)               as start_time\n    max(_time)               as end_time\n    values(EventCode)        as stages\n    count                    as event_count\n    values(relying_party_raw) as rps_raw\n    values(auth_protocol)     as protos\n    values(redirect_uri)      as redirect_uri\n    values(redirect_host)     as redirect_host\n    values(host)              as servers\n    values(proxy_server)      as proxy_servers\n    values(user)              as users\n    max(mfa_flag)             as mfa_flag\n    values(mfa_method)        as mfa_methods\n  by activity_id\n| eval mfa         = if(mfa_flag==1, \"MFA\", \"No MFA\")\n| eval mfa_method  = mvindex(mfa_methods, 0)\n| eval rps_raw     = mvdedup(rps_raw)\n| eval rp_clean    = mvfilter(rps_raw!=\"WS-Trust endpoint (legacy clients)\" AND rps_raw!=\"https://host.example.gov/[redacted-path] eval relying_party = coalesce(mvindex(rp_clean, 0), mvindex(rps_raw, 0))\n| lookup ADFS_friendly_names url as relying_party       output friendlyName as rp_friendly\n| eval relying_party = coalesce(rp_friendly, relying_party)\n| eval proto_raw   = lower(mvindex(mvfilter(len(protos)>0),0))\n| eval protocol    = case(\n    match(proto_raw,\"oauth\"), \"OIDC\",\n    match(proto_raw,\"saml\"),  \"SAML\",\n    match(proto_raw,\"wsfed\"), \"WS-Fed\",\n    1=1,                       \"Other\"\n  )\n| eval user        = mvindex(users, 0)\n| lookup ADFS_friendly_names url as redirect_host      output friendlyName as uri_friendly_host\n| lookup ADFS_friendly_names.csv url as redirect_uri       output friendlyName as uri_friendly_full\n| eval uri_friendly = coalesce(uri_friendly_full, uri_friendly_host)\n| eval is_proxy    = if(mvcount(mvfilter(proxy_servers!=\"N/A\"))>0,1,0)\n| eval cred_ok     = if(mvfind(stages,\"1202\")>=0,1,0)\n| eval cred_fail   = if(mvfind(stages,\"1203\")>=0,1,0)\n| eval token_ok    = if(mvfind(stages,\"1200\")>=0,1,0)\n| eval token_fail  = if(mvfind(stages,\"1201\")>=0,1,0)\n| eval outcome     = case(\n    token_ok==1 AND cred_ok==1,  \"Success\",\n    token_fail==1,                \"Token Failure\",\n    cred_fail==1,                 \"Credential Failure\",\n    1=1,                          \"Other\"\n  )\n| where outcome!=\"Other\"\n| lookup adfs_event_codes code as stages output label as stage_word\n| eval stage_seq   = mvjoin(mvzip(stages, stage_word, \" \"), \" -> \")\n| eval duration_sec= round(end_time-start_time,2)\n| eval time        = strftime(start_time, \"%Y-%m-%d %H:%M:%S\")\n| eval application = case(protocol==\"OIDC\", coalesce(uri_friendly, redirect_uri), 1=1, relying_party)\n| eval app_url     = coalesce(redirect_uri, mvindex(rp_clean,0), mvindex(rps_raw,0))\n| eval flow        = case(is_proxy==1, \"WAP->ADFS\", 1=1, \"ADFS-only\")\n| eval mfa_method_label = case(\n    mfa_method==\"MFA\", \"Duo Push (fresh MFA)\",\n    mfa_method==\"SSO\", \"Session SSO (no new MFA)\",\n    mfa_method==\"N/A\", \"No MFA (App Policy)\",\n    1=1,               \"Unknown\"\n  )\n| rename\n    time             as Time,\n    user             as User,\n    application      as Application,\n    protocol         as Protocol,\n    flow             as Flow,\n    outcome          as Result,\n    app_url          as \"App URL\",\n    duration_sec     as Duration,\n    stage_seq        as \"Stage Seq\",\n    event_count      as Events,\n    mfa              as MFA,\n    mfa_method_label as \"MFA Method\",\n    activity_id      as \"Activity ID\"\n| stats count(eval('MFA Method'=\"Session SSO (no new MFA)\")) as \"Session SSO (no new MFA)\"",
